<?php
namespace CargoDocsStudio\Database\Schema;
class FieldsTable extends AbstractTable { public function create(): void { global $wpdb; $table=$wpdb->prefix.'cds_fields'; $collate=$wpdb->get_charset_collate(); $this->runSql("CREATE TABLE $table (id bigint unsigned NOT NULL AUTO_INCREMENT, field_key varchar(128) NOT NULL, doc_type_key varchar(64) NOT NULL, label varchar(191) NOT NULL, type varchar(64) NOT NULL, rules_json longtext NULL, default_json longtext NULL, ui_json longtext NULL, pii_flag tinyint(1) NOT NULL DEFAULT 0, active tinyint(1) NOT NULL DEFAULT 1, created_at datetime NOT NULL, updated_at datetime NOT NULL, PRIMARY KEY (id), KEY doc_type_key (doc_type_key), UNIQUE KEY field_key_doc (field_key,doc_type_key)) $collate;"); } }
